<template><section class="space-y-6"><div><h1 class="text-3xl font-black text-white">Settings</h1><p class="text-slate-400">Runtime config, feature flags, theme, table density, and connection tests.</p></div><div class="card p-5"><dl class="grid gap-4 md:grid-cols-2"><div v-for="item in items" :key="item.label"><dt class="text-sm text-slate-400">{{ item.label }}</dt><dd class="font-mono text-sm text-white">{{ item.value }}</dd></div></dl><div class="mt-5 flex flex-wrap gap-3"><button class="button-secondary" @click="testCore">Test core</button><button class="button-secondary" @click="testEdge">Test edge</button><button class="button-secondary" @click="ui.toggleDarkMode">Toggle theme</button><button class="button-secondary" @click="edge.clear">Clear session edge credentials</button></div><pre class="mt-4 rounded-xl bg-slate-950 p-4 text-xs">{{ JSON.stringify(result, null, 2) }}</pre></div><div class="card p-5 text-sm text-amber-200">Production security note: put this SPA and the CDNLite API behind real authentication at the reverse proxy or platform level. This client-only dashboard does not implement production RBAC.</div></section></template>
<script setup lang="ts">
import { computed, ref } from 'vue'; import { runtimeConfig, hasApiToken } from '@/lib/config/env'; import { healthApi } from '@/lib/api/health'; import { useUiStore } from '@/stores/ui'; import { useEdgeSessionStore } from '@/stores/edgeSession';
const ui = useUiStore(); const edge = useEdgeSessionStore(); const result = ref<unknown>(null);
const items = computed(() => [{ label: 'Core URL', value: runtimeConfig.coreUrl }, { label: 'Edge URL', value: runtimeConfig.edgeUrl }, { label: 'App name', value: runtimeConfig.appName }, { label: 'Request timeout', value: `${runtimeConfig.requestTimeoutMs} ms` }, { label: 'Refresh interval', value: `${runtimeConfig.dashboardRefreshSeconds} s` }, { label: 'API token', value: hasApiToken() ? 'configured' : 'not configured' }, { label: 'Edge dev tools', value: String(runtimeConfig.edgeDevTools) }, { label: 'Usage simulator', value: String(runtimeConfig.usageSimulator) }, { label: 'SSL tools', value: String(runtimeConfig.sslTools) }, { label: 'Security event viewer', value: String(runtimeConfig.securityEventViewer) }]);
async function testCore() { result.value = await Promise.allSettled([healthApi.coreHealth(), healthApi.coreReady()]); } async function testEdge() { result.value = await healthApi.edgeReady(); }
</script>
